// Regression fixture for re-export clobbering.
//
// `module.exports = require('./named')` registers `./named` as a re-export
// (`export *`). The subsequent `module.exports = { ... }` reassignment must
// discard that re-export: Node would only expose `bar` here, never `foo`. If
// the analyzer retains the stale re-export, `foo` leaks onto this module's
// namespace.
//
// `bar` uses a bare-identifier (shorthand) value on purpose: the CJS lexer
// only records an object-literal key when the value *begins* with an
// identifier, so a non-identifier value like `bar: 'bar'` would not be
// statically detected.
const bar = 'bar';
module.exports = require('./named');
module.exports = {
  bar,
};
